-- PostgreSQL Schema for VendoHub Database\n\n-- Table for users with roles\nCREATE TABLE users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(255) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    role VARCHAR(50) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for companies with RUC\nCREATE TABLE companies (\n    company_id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    ruc VARCHAR(11) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for customers with RUC/DNI\nCREATE TABLE customers (\n    customer_id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    dni VARCHAR(8),\n    ruc VARCHAR(11),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for products with categories\nCREATE TABLE products (\n    product_id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    category VARCHAR(50) NOT NULL,\n    price DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for sales with invoice type\nCREATE TABLE sales (\n    sale_id SERIAL PRIMARY KEY,\n    customer_id INT REFERENCES customers(customer_id),\n    invoice_type VARCHAR(50) NOT NULL,\n    total DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for inventory tracking stock levels and movements\nCREATE TABLE inventory (\n    inventory_id SERIAL PRIMARY KEY,\n    product_id INT REFERENCES products(product_id),\n    stock_level INT NOT NULL,\n    movement_type VARCHAR(50) NOT NULL,\n    quantity INT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for reports for SUNAT compliance\nCREATE TABLE reports (\n    report_id SERIAL PRIMARY KEY,\n    sale_id INT REFERENCES sales(sale_id),\n    report_date DATE NOT NULL,\n    compliance_status VARCHAR(50) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n